{"output":"/// Performance profiling helper for scroll performance testing with Flutter DevTools
///
/// Usage:
/// 1. Run app in profile mode: `flutter run --profile`
/// 2. Open Flutter DevTools Performance tab
/// 3. Navigate to inspection form with large dataset
/// 4. Start recording in DevTools
/// 5. Perform scrolling actions
/// 6. Stop recording and analyze:
///    - Frame rendering time should be <16.67ms (60fps)
///    - No dropped frames during scroll
///    - Shader compilation should be <50ms
///
/// Target Metrics (AC 3.1B.6):
/// - 60fps scrolling maintained (16.67ms per frame)
/// - Schema rendering: <500ms for 50 fields
/// - Widget factory: <50ms per field
/// - Smooth animations with no jank
library;

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

/// Performance monitoring wrapper for scroll widgets
class ScrollPerformanceMonitor extends StatefulWidget {
  final Widget child;
  final String label;
  final Function(ScrollPerformanceMetrics)? onMetricsUpdate;

  const ScrollPerformanceMonitor({
    super.key,
    required this.child,
    this.label = 'ScrollView',
    this.onMetricsUpdate,
  });

  @override
  State<ScrollPerformanceMonitor> createState() =>
      _ScrollPerformanceMonitorState();
}

class _ScrollPerformanceMonitorState extends State<ScrollPerformanceMonitor> {
  final _metrics = ScrollPerformanceMetrics();
  Stopwatch? _scrollStopwatch;

  @override
  Widget build(BuildContext context) {
    return NotificationListener<ScrollNotification>(
      onNotification: (notification) {
        if (kProfileMode || kDebugMode) {
          _handleScrollNotification(notification);
        }
        return false;
      },
      child: widget.child,
    );
  }

  void _handleScrollNotification(ScrollNotification notification) {
    if (notification is ScrollStartNotification) {
      _scrollStopwatch = Stopwatch()..start();
      _metrics.scrollCount++;
    } else if (notification is ScrollEndNotification) {
      _scrollStopwatch?.stop();
      final duration = _scrollStopwatch?.elapsedMilliseconds ?? 0;
      _metrics.totalScrollDuration += duration;
      _metrics.averageScrollDuration =
          _metrics.totalScrollDuration / _metrics.scrollCount;

      if (kDebugMode) {
        debugPrint(
          '[${widget.label}] Scroll completed in ${duration}ms '
          '(avg: ${_metrics.averageScrollDuration.toStringAsFixed(1)}ms)',
        );
      }

      widget.onMetricsUpdate?.call(_metrics);
    } else if (notification is ScrollUpdateNotification) {
      final pixelsScrolled = notification.scrollDelta?.abs() ?? 0;
      _metrics.totalPixelsScrolled += pixelsScrolled;
    }
  }
}

/// Scroll performance metrics
class ScrollPerformanceMetrics {
  int scrollCount = 0;
  int totalScrollDuration = 0;
  double averageScrollDuration = 0.0;
  double totalPixelsScrolled = 0.0;

  Map<String, dynamic> toJson() => {
        'scroll_count': scrollCount,
        'total_scroll_duration_ms': totalScrollDuration,
        'average_scroll_duration_ms': averageScrollDuration,
        'total_pixels_scrolled': totalPixelsScrolled,
      };
}

