/// Test Data Factory for Inspection
/// Provides helper methods to generate test inspections with various configurations
///
/// Usage:
/// ```dart
/// final inspection = InspectionFactory.create();
/// final submittedInspection = InspectionFactory.create(status: InspectionStatus.submitted);
/// final inspections = InspectionFactory.createMultiple(10);
/// ```

class InspectionFactory {
  /// Create single inspection with optional overrides
  static Inspection create({
    String? id,
    String? templateId,
    String? formDataJson,
    InspectionStatus status = InspectionStatus.draft,
    int? createdAt,
    int? updatedAt,
    int? syncedAt,
  }) {
    final now = DateTime.now().millisecondsSinceEpoch;
    return Inspection(
      id: id ?? 'inspection-$now-${_randomSuffix()}',
      templateId: templateId ?? 'template-${_randomSuffix()}',
      formDataJson: formDataJson ?? '{"field1": "value1", "field2": "value2"}',
      status: status,
      createdAt: createdAt ?? now,
      updatedAt: updatedAt ?? now,
      syncedAt: syncedAt,
    );
  }

  /// Create multiple inspections
  static List<Inspection> createMultiple(
    int count, {
    InspectionStatus? status,
    String? templateId,
  }) {
    return List.generate(
      count,
      (i) => create(
        id: 'inspection-$i-${DateTime.now().millisecondsSinceEpoch}',
        templateId: templateId ?? 'template-$i',
        status: status ?? InspectionStatus.draft,
      ),
    );
  }

  /// Create inspection with large form data (for performance testing)
  static Inspection createLarge({
    int fieldCount = 50,
    InspectionStatus status = InspectionStatus.draft,
  }) {
    final fields = { for (var field in List.generate(fieldCount, (i) => 'field_$i')) field : 'value_${field}_${_randomSuffix()}' };

    return create(
      formDataJson: _toJson(fields),
      status: status,
    );
  }

  /// Create inspection in specific status
  static Inspection createDraft({String? id, String? templateId}) {
    return create(
      id: id,
      templateId: templateId,
      status: InspectionStatus.draft,
    );
  }

  static Inspection createSubmitted({String? id, String? templateId}) {
    return create(
      id: id,
      templateId: templateId,
      status: InspectionStatus.submitted,
    );
  }

  static Inspection createApproved({String? id, String? templateId}) {
    return create(
      id: id,
      templateId: templateId,
      status: InspectionStatus.approved,
    );
  }

  static Inspection createRejected({String? id, String? templateId}) {
    return create(
      id: id,
      templateId: templateId,
      status: InspectionStatus.rejected,
    );
  }

  /// Create conflict scenario (local vs server)
  static ConflictScenario createConflict({
    String? id,
    int localTimestamp = 1000,
    int serverTimestamp = 2000,
  }) {
    final conflictId = id ?? 'inspection-conflict-${DateTime.now().millisecondsSinceEpoch}';

    return ConflictScenario(
      local: create(
        id: conflictId,
        formDataJson: '{"field": "local_value"}',
        updatedAt: localTimestamp,
      ),
      server: create(
        id: conflictId,
        formDataJson: '{"field": "server_value", "lastModifiedBy": "john.doe@example.com"}',
        updatedAt: serverTimestamp,
      ),
    );
  }

  /// Create approved inspection conflict (should reject server changes)
  static ConflictScenario createApprovedConflict({String? id}) {
    final conflictId = id ?? 'inspection-approved-conflict-${DateTime.now().millisecondsSinceEpoch}';

    return ConflictScenario(
      local: create(
        id: conflictId,
        status: InspectionStatus.approved,
        formDataJson: '{"field": "local_approved"}',
        updatedAt: 1000,
      ),
      server: create(
        id: conflictId,
        status: InspectionStatus.approved,
        formDataJson: '{"field": "server_changed"}',
        updatedAt: 2000,
      ),
    );
  }

  /// Create inspection with realistic data
  static Inspection createRealistic({
    InspectionStatus status = InspectionStatus.draft,
  }) {
    return create(
      formDataJson: '''
      {
        "inspector_name": "John Doe",
        "inspection_date": "2025-10-30",
        "asset_id": "ASSET-${_randomSuffix()}",
        "condition": "Good",
        "notes": "Routine inspection completed. No issues found.",
        "defects_found": 0,
        "photos_count": 5,
        "gps_location": "40.7128,-74.0060",
        "temperature_celsius": 22.5,
        "humidity_percent": 65
      }
      ''',
      status: status,
    );
  }

  // Helper methods
  static String _randomSuffix() {
    return DateTime.now().microsecondsSinceEpoch.toString().substring(8);
  }

  static String _toJson(Map<String, dynamic> data) {
    final entries = data.entries.map((e) => '"${e.key}": "${e.value}"').join(', ');
    return '{$entries}';
  }
}

/// Helper class for conflict resolution testing
class ConflictScenario {
  final Inspection local;
  final Inspection server;

  ConflictScenario({
    required this.local,
    required this.server,
  });
}
