InspectionStatus inspectionStatusFromString(String value) {
  switch (value) {
    case 'draft':
      return InspectionStatus.draft;
    case 'queued':
      return InspectionStatus.queued;
    case 'synced':
      return InspectionStatus.synced;
    case 'submitted':
      return InspectionStatus.submitted;
    case 'approved':
      return InspectionStatus.approved;
    default:
      return InspectionStatus.draft;
  }
}

String inspectionStatusToString(InspectionStatus status) {
