  /// Parse JSON schema and return template schema
  /// Tracks performance and manages loading state
  Future<TemplateSchema> parseSchema(String schemaJson) async {
    final stopwatch = Stopwatch()..start();

    try {
      _setLoading(true);
      final schema = await _parser.parse(schemaJson);

      stopwatch.stop();
      _recordPerformance(stopwatch.elapsedMilliseconds);

      return schema;
    } finally {
      _setLoading(false);
