    Map<String, widget_factory.FieldUiState> uiStates,
  ) async {
    final stopwatch = Stopwatch()..start();

    try {
      _setLoading(true);

      final widgets = <Widget>[];

      for (final section in schema.sections) {
        // Add section header
        widgets.add(_buildSectionHeader(section));

        // Render all fields in section
        for (final field in section.fields) {
          final uiState = uiStates[field.id] ?? widget_factory.FieldUiState();
          final widget = _widgetFactory.createField(field, formState, uiState);
          widgets.add(widget);
          widgets.add(const SizedBox(height: 16)); // Spacing between fields
        }

        widgets.add(const SizedBox(height: 24)); // Spacing between sections
      }

      stopwatch.stop();
      _recordPerformance(stopwatch.elapsedMilliseconds);

      return widgets;
    } finally {
      _setLoading(false);
    }
  }

  /// Complete render pipeline: parse schema + render widgets
  /// This is the main entry point for form rendering
