      // Gets current form values from formState and evaluates visibility/disabled/required rules
      final formValues = <String, dynamic>{};
      for (final section in schema.sections) {
        for (final field in section.fields) {
          formValues[field.id] = formState.getValue(field.id);
        }
      }
      final evaluatedStates = _conditionalLogic.evaluateForm(
        schema,
