/// Global accessor for the currently active startup options.
class AppStartupConfig {
  static AppStartupOptions _options = AppStartupOptions.production();

  static AppStartupOptions get options => _options;

  @visibleForTesting
  static void overrideForTests(AppStartupOptions options) {
    _options = options;
  }

  @visibleForTesting
  static void reset() {
    _options = AppStartupOptions.production();
  }
}

/// Tracks cold-start metrics such as time-to-first-frame.
class AppStartupTracker {
  static Stopwatch? _stopwatch;
  static Completer<Duration>? _firstFrameCompleter;

  static void start() {
    _stopwatch = Stopwatch()..start();
    _firstFrameCompleter = Completer<Duration>();
  }

  static void markFirstFrame() {
    if (_stopwatch == null) {
      return;
    }
    if (_stopwatch!.isRunning) {
      _stopwatch!.stop();
    }
    final duration = _stopwatch!.elapsed;
    if (!(_firstFrameCompleter?.isCompleted ?? true)) {
      _firstFrameCompleter!.complete(duration);
    }
    debugPrint(
      'PERF_STARTUP_FIRST_FRAME_MS=${duration.inMilliseconds}',
    );
  }

  static Duration? get timeToFirstFrame =>
      _firstFrameCompleter?.isCompleted == true
          ? _stopwatch?.elapsed
          : null;

  static Future<Duration> waitForFirstFrame({Duration? timeout}) {
    final completer = _firstFrameCompleter;
    if (completer == null) {
      return Future.error(StateError('AppStartupTracker not started'));
    }
    return timeout == null
        ? completer.future
        : completer.future.timeout(timeout);
  }

  @visibleForTesting
  static void reset() {
    _stopwatch?.stop();
    _stopwatch = null;
    _firstFrameCompleter = null;
  }
}
